.dp-dashboard {
  display: flex;
  flex-direction: column;
  gap: 20px;
  height: 100%;
  color: var(--text-color);
  animation: fadeIn 0.5s ease-in-out;
}
@keyframes fadeIn { from { opacity: 0; transform: translateY(10px); } to { opacity: 1; transform: translateY(0); } }

.dp-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  background: linear-gradient(135deg, #1e293b, #0f172a);
  padding: 20px 30px;
  border-radius: 12px;
  border: 1px solid var(--border);
  box-shadow: 0 4px 15px rgba(0,0,0,0.2);
}
.dp-title {
  font-size: 1.5rem;
  font-weight: 600;
  color: #38bdf8;
  display: flex;
  align-items: center;
  gap: 10px;
}
.dp-stats {
  display: flex;
  gap: 20px;
}
.stat-box {
  background: rgba(255,255,255,0.05);
  padding: 10px 20px;
  border-radius: 8px;
  display: flex;
  flex-direction: column;
  align-items: center;
  border: 1px solid rgba(255,255,255,0.1);
}
.stat-label { font-size: 0.8rem; color: #94a3b8; text-transform: uppercase; letter-spacing: 1px; }
.stat-value { font-size: 1.5rem; font-weight: 700; color: #f8fafc; }
.stat-value.highlight { color: #f43f5e; }

.dp-main {
  display: grid;
  grid-template-columns: 300px 1fr;
  gap: 20px;
  flex: 1;
}

.dp-controls {
  background: var(--surface);
  padding: 24px;
  border-radius: 12px;
  border: 1px solid var(--border);
  display: flex;
  flex-direction: column;
  gap: 15px;
}
.dp-controls h3 { margin-top: 0; color: #e2e8f0; border-bottom: 1px solid var(--border); padding-bottom: 10px; }

.step-container { margin-bottom: 10px; }
.step-desc { font-size: 0.8rem; color: #94a3b8; margin-top: 5px; padding-left: 5px; }

.dp-btn {
  width: 100%;
  text-align: left;
  background: #2563eb;
  padding: 12px 15px;
  font-size: 1rem;
  border-radius: 8px;
  display: flex;
  align-items: center;
  gap: 10px;
  box-shadow: 0 4px 6px rgba(0,0,0,0.1);
}
.dp-btn:hover:not(:disabled) { background: #1d4ed8; transform: translateY(-2px); box-shadow: 0 6px 12px rgba(37,99,235,0.2); }
.dp-btn:disabled { background: #334155; color: #64748b; cursor: not-allowed; box-shadow: none; transform: none; }

.dp-btn-reset {
  width: 100%;
  background: transparent;
  border: 1px solid #f43f5e;
  color: #f43f5e;
  padding: 10px;
  border-radius: 8px;
  cursor: pointer;
  margin-top: 20px;
  transition: all 0.2s;
}
.dp-btn-reset:hover { background: #f43f5e; color: white; }

.dp-view {
  background: var(--surface);
  padding: 24px;
  border-radius: 12px;
  border: 1px solid var(--border);
  display: flex;
  flex-direction: column;
  gap: 20px;
}
.dp-view h3 { margin-top: 0; color: #e2e8f0; border-bottom: 1px solid var(--border); padding-bottom: 10px; }

.table-container {
  overflow-x: auto;
  border-radius: 8px;
  border: 1px solid var(--border);
}
table { margin-bottom: 0; }
th { background: #0f172a; color: #cbd5e1; }
td { color: #f8fafc; font-family: monospace; font-size: 1.1rem; }
td.null-val { color: #f43f5e; font-weight: bold; font-style: italic; }
td.updated { color: #10b981; animation: flashGreen 1s ease-out; }
@keyframes flashGreen { 0% { background-color: rgba(16,185,129,0.5); } 100% { background-color: transparent; } }

.chart-container {
  height: 300px;
  width: 100%;
  margin-top: 20px;
  background: rgba(15,23,42,0.5);
  border-radius: 8px;
  padding: 15px;
}

