const initialData = [
  { id: 1, age: 25, salary: 50000, dept: 'Sales' },
  { id: 2, age: null, salary: 60000, dept: 'HR' },
  { id: 3, age: 30, salary: 55000, dept: 'IT' },
  { id: 4, age: 40, salary: null, dept: 'Sales' },
  { id: 5, age: 35, salary: 80000, dept: 'IT' }
];

let currentData = JSON.parse(JSON.stringify(initialData));
let step1Done = false;
let step2Done = false;
let step3Done = false;
let chartInstance = null;

function renderTable(highlightField = null) {
  const tbody = document.getElementById('tableBody');
  tbody.innerHTML = '';
  let missing = 0;

  currentData.forEach((row, i) => {
    const tr = document.createElement('tr');

    // ID
    tr.innerHTML += `<td>${row.id}</td>`;

    // Age
    if (row.age === null) {
      tr.innerHTML += `<td class="null-val">NaN</td>`;
      missing++;
    } else {
      const isUpdated = highlightField === 'age' && initialData[i].age !== row.age;
      tr.innerHTML += `<td class="${isUpdated ? 'updated' : ''}">${typeof row.age === 'number' && !Number.isInteger(row.age) ? row.age.toFixed(2) : row.age}</td>`;
    }

    // Salary
    if (row.salary === null) {
      tr.innerHTML += `<td class="null-val">NaN</td>`;
      missing++;
    } else {
      const isUpdated = highlightField === 'salary' && initialData[i].salary !== row.salary;
      tr.innerHTML += `<td class="${isUpdated ? 'updated' : ''}">${typeof row.salary === 'number' && !Number.isInteger(row.salary) && row.salary < 10 ? row.salary.toFixed(3) : row.salary}</td>`;
    }

    // Dept
    const isUpdated = highlightField === 'dept' && initialData[i].dept !== row.dept;
    tr.innerHTML += `<td class="${isUpdated ? 'updated' : ''}">${row.dept}</td>`;

    tbody.appendChild(tr);
  });

  document.getElementById('missingCount').innerText = missing;
  if (missing === 0) {
    document.getElementById('missingCount').classList.remove('highlight');
    document.getElementById('missingCount').style.color = '#10b981';
  } else {
    document.getElementById('missingCount').classList.add('highlight');
    document.getElementById('missingCount').style.color = '';
  }

  updateChart();
}

function handleMissing() {
  let ageSum = 0, ageCount = 0;
  let salSum = 0, salCount = 0;

  currentData.forEach(r => {
    if (r.age !== null) { ageSum += r.age; ageCount++; }
    if (r.salary !== null) { salSum += r.salary; salCount++; }
  });

  const ageMean = Math.round(ageSum / ageCount);
  const salMean = Math.round(salSum / salCount);

  currentData.forEach(r => {
    if (r.age === null) r.age = ageMean;
    if (r.salary === null) r.salary = salMean;
  });

  step1Done = true;
  document.getElementById('btnMissing').disabled = true;
  document.getElementById('btnMissing').innerHTML = '<i class="fa-solid fa-check"></i> 1. Missing Values Handled';
  document.getElementById('btnNormalize').disabled = false;

  renderTable('age'); // or salary, both get highlighted if changed
}

function normalizeData() {
  const ages = currentData.map(r => r.age);
  const sals = currentData.map(r => r.salary);
  const minAge = Math.min(...ages), maxAge = Math.max(...ages);
  const minSal = Math.min(...sals), maxSal = Math.max(...sals);

  currentData.forEach(r => {
    r.age = (r.age - minAge) / (maxAge - minAge);
    r.salary = (r.salary - minSal) / (maxSal - minSal);
  });

  step2Done = true;
  document.getElementById('btnNormalize').disabled = true;
  document.getElementById('btnNormalize').innerHTML = '<i class="fa-solid fa-check"></i> 2. Data Normalized';
  document.getElementById('btnEncode').disabled = false;

  renderTable('salary');
}

function encodeData() {
  const deptMap = { 'Sales': 0, 'HR': 1, 'IT': 2 };

  currentData.forEach(r => {
    r.dept = deptMap[r.dept];
  });

  step3Done = true;
  document.getElementById('btnEncode').disabled = true;
  document.getElementById('btnEncode').innerHTML = '<i class="fa-solid fa-check"></i> 3. Categorical Encoded';

  renderTable('dept');
}

function resetData() {
  currentData = JSON.parse(JSON.stringify(initialData));
  step1Done = false;
  step2Done = false;
  step3Done = false;

  const btnM = document.getElementById('btnMissing');
  btnM.disabled = false;
  btnM.innerHTML = '<i class="fa-solid fa-wand-magic-sparkles"></i> 1. Handle Missing Values';

  const btnN = document.getElementById('btnNormalize');
  btnN.disabled = true;
  btnN.innerHTML = '<i class="fa-solid fa-scale-balanced"></i> 2. Normalize Data';

  const btnE = document.getElementById('btnEncode');
  btnE.disabled = true;
  btnE.innerHTML = '<i class="fa-solid fa-tags"></i> 3. Encode Categorical';

  renderTable();
}

function updateChart() {
  const ctx = document.getElementById('dataChart').getContext('2d');

  const labels = currentData.map(r => 'ID ' + r.id);
  const ages = currentData.map(r => r.age === null ? 0 : r.age);

  // If normalized, salaries are small, if not they are huge. We scale salary for visual purposes if not normalized
  const sals = currentData.map(r => {
    if (r.salary === null) return 0;
    return step2Done ? r.salary : r.salary / 1000; // divide by 1k for visual scale before norm
  });

  if (chartInstance) {
    chartInstance.destroy();
  }

  chartInstance = new Chart(ctx, {
    type: 'bar',
    data: {
      labels: labels,
      datasets: [
        {
          label: step2Done ? 'Normalized Age' : 'Age',
          data: ages,
          backgroundColor: 'rgba(56, 189, 248, 0.7)',
          borderColor: 'rgba(56, 189, 248, 1)',
          borderWidth: 1
        },
        {
          label: step2Done ? 'Normalized Salary' : 'Salary (in thousands)',
          data: sals,
          backgroundColor: 'rgba(16, 185, 129, 0.7)',
          borderColor: 'rgba(16, 185, 129, 1)',
          borderWidth: 1
        }
      ]
    },
    options: {
      responsive: true,
      maintainAspectRatio: false,
      plugins: {
        legend: { labels: { color: '#e2e8f0' } }
      },
      scales: {
        y: { ticks: { color: '#94a3b8' }, grid: { color: 'rgba(255,255,255,0.1)' } },
        x: { ticks: { color: '#94a3b8' }, grid: { display: false } }
      }
    }
  });
}

// Initial render
setTimeout(renderTable, 100);
